#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#define MAXN 1000
#define MAXM 1000
#define MAXVAL 1000

int grid[MAXN][MAXM];
int dist[MAXN][MAXM];
int visited[MAXN][MAXM];
int dx[] = {-1, 1, 0, 0};
int dy[] = {0, 0, -1, 1};

void bfs(int x, int y, int n, int m) {
    int queue[MAXN * MAXM][2];
    int front = 0, rear = 0;
    queue[rear][0] = x;
    queue[rear++][1] = y;
    visited[x][y] = 1;
    dist[x][y] = grid[x][y];
    while (front < rear) {
        int currX = queue[front][0];
        int currY = queue[front++][1];
        for (int i = 0; i < 4; i++) {
            int newX = currX + dx[i];
            int newY = currY + dy[i];
            if (newX >= 0 && newX < n && newY >= 0 && newY < m && grid[newX][newY] != -1 && !visited[newX][newY]) {
                queue[rear][0] = newX;
                queue[rear++][1] = newY;
                visited[newX][newY] = 1;
                dist[newX][newY] = dist[currX][currY] + 1;
            }
        }
    }
}

int main() {
    int t;
    scanf("%d", &t);
    while (t--) {
        int n, m;
        scanf("%d %d", &n, &m);
        for (int i = 0; i < n; i++) {
            for (int j = 0; j < m; j++) {
                scanf("%d", &grid[i][j]);
                visited[i][j] = 0;
                dist[i][j] = MAXVAL;
            }
        }
        for (int i = 0; i < n; i++) {
            for (int j = 0; j < m; j++) {
                if (grid[i][j] > 0) {
                    bfs(i, j, n, m);
                }
            }
        }
        for (int i = 0; i < n; i++) {
            for (int j = 0; j < m; j++) {
                if (grid[i][j] == -1) {
                    printf("B");
                } else if (dist[i][j] <= grid[i][j]) {
                    printf("Y");
                } else {
                    printf("N");
                }
            }
            printf("\n");
        }
    }
    return 0;
}

