def bfs(x, y, n, m, grid, dist, visited):
    q = deque([(x, y)])
    visited[x][y] = True
    dist[x][y] = grid[x][y]
    while q:
        currX, currY = q.popleft()
        for i in range(4):
            newX, newY = currX + dx[i], currY + dy[i]
            if 0 <= newX < n and 0 <= newY < m and grid[newX][newY] != -1 and not visited[newX][newY]:
